	private static boolean isFiniteAssignment(BindingSetAssignment assignment) {
		boolean hasRows = false;
		for (BindingSet bindingSet : assignment.getBindingSets()) {
			hasRows = true;
			for (String bindingName : assignment.getBindingNames()) {
				if (bindingSet.getValue(bindingName) == null) {
					return false;
				}
			}
		}
		return hasRows;
	}

	private static TupleExpr leftDeep(List<TupleExpr> factors) {
		TupleExpr root = factors.getFirst();
		for (int index = 1; index < factors.size(); index++) {
			root = new Join(root, factors.get(index));
		}
		return root;
	}

	private static boolean requiresAnyBinding(List<TupleExpr> factors, Set<String> bindingNames) {
		if (bindingNames.isEmpty()) {
			return false;
		}
		for (TupleExpr factor : factors) {
			if (!java.util.Collections.disjoint(LmdbJoinIslandConnectivity.opaqueFactorRequiredVars(factor),
					bindingNames)) {
				return true;
			}
		}
		return false;
	}

